sql:
SELECT e.exchange_name, s.stock_name
FROM exchanges e
JOIN stocks s ON e.exchange_id = s.exchange_id;

SELECT open_price, high_price, close_price
FROM market_data
WHERE stock_id = 102 AND timestamp BETWEEN '2020-01-01' AND '2020-12-31';

SELECT DISTINCT s.stock_id
FROM stocks s
WHERE s.market_cap > 100000000;

SELECT user_id, user_name, role, last_login
FROM users
WHERE role = 'analyst' AND strftime('%J', 'now') - strftime('%J', last_login) > 30;

SELECT compliance_score 
FROM compliance
WHERE compliance_id = 1;

